record.field:
if (bom := (custom_bom := record.x_bom_id)):
    # if it's not already done: immediately create a copy for this SOL
    if bom.x_original_sol_id.id != (so := record.order_id).id:
        expected_code = f"{so.name} - {so.partner_id.name}" + f" - {bom.code}" * bool(bom.code)

        custom_bom = bom.copy({'code': expected_code, 'x_original_sol_id': record.id, 'x_parent_bom_id': bom.id})
        record['x_bom_id'] = custom_bom.id

    action = {'type': 'ir.actions.act_window', 'name': f'Configure Order BOM: {custom_bom.code}', 'view_mode': 'form', 'target': 'new',
              'res_model': 'mrp.bom', 'res_id': custom_bom.id}
